('partner.poscenter.categories', '[{"icon":"Monitor","name":"POS-терминалы","desc":"Моноблоки и сенсорные терминалы для торговых точек, ресторанов и сервисных центров."},{"icon":"Printer","name":"Фискальные регистраторы","desc":"Автономные ФР для подключения к любому компьютеру или кассовой системе."},{"icon":"ScanBarcode","name":"Терминалы сбора данных","desc":"ТСД на Android для автоматизации склада, инвентаризации и приёмки товаров."},{"icon":"Smartphone","name":"Мобильные принтеры","desc":"Компактные принтеры этикеток и чеков для мобильных сотрудников."},{"icon":"Tag","name":"Принтеры этикеток","desc":"Настольные принтеры для печати ценников, штрихкодов и этикеток с маркировкой."},{"icon":"Scan","name":"Сканеры штрихкодов","desc":"Ручные и стационарные сканеры для торговли и склада."}]'),
('partner.poscenter.advantages', '[{"icon":"Factory","text":"Собственное производство"},{"icon":"MapPin","text":"Сервисные центры по всей России"},{"icon":"ShieldCheck","text":"Гарантия 1–3 года"},{"icon":"Truck","text":"Доставка по всей России"},{"icon":"BadgeCheck","text":"Соответствие 54-ФЗ"},{"icon":"Headphones","text":"Техподдержка 24/7"}]'),
('partner.ofd_yandex.features', '[{"icon":"Send","name":"Передача данных в ФНС","desc":"Автоматическая передача фискальных данных со всех ваших касс в ФНС в режиме реального времени."},{"icon":"BarChart3","name":"Аналитика продаж","desc":"Детальная статистика по чекам, выручке, среднему чеку и топ-товарам."},{"icon":"Bell","name":"Мониторинг касс","desc":"Оперативные уведомления о проблемах с кассами: нет связи, заполнен ФН, ошибки."},{"icon":"Shield","name":"Надёжное хранение","desc":"Все фискальные документы хранятся в защищённом облаке Яндекса."},{"icon":"FileSearch","name":"Электронные чеки","desc":"Отправка чеков покупателям на email и телефон. Хранение истории всех транзакций."},{"icon":"Zap","name":"Быстрое подключение","desc":"Подключение кассы к ОФД занимает несколько минут."}]'),
